242	const beginDescendTransition = (
243	  get: StoreGet,
244	  set: StoreSet,
245	): void => {
246	  const { gameSession, gameState } = get();
247	  if (gameSession === null || gameState === null || get().transition !== null) {
248	    return;
249	  }
250	
251	  const nextDepth = gameState.run.depth + 1;
252	  const startedAtMs = nowMs();
253	  set({
254	    ui: { ...get().ui, inputLocked: true },
255	    transition: createDescendingTransition({
256	      depth: nextDepth,
257	      whisper: floorIntroFromState(gameState),
258	      controllerState: "none",
259	      startedAtMs,
260	    }),
261	    arrivalIntroLine: null,
262	  });
263	
264	  void resolveTransitionFloor({
265	    get,
266	    set,
267	    session: gameSession,
268	    depth: nextDepth,
269	    startedAtMs,
270	  });
271	};
