273	const resolveTransitionFloor = async ({
274	  get,
275	  set,
276	  session,
277	  depth,
278	  startedAtMs,
279	}: {
280	  readonly get: StoreGet;
281	  readonly set: StoreSet;
282	  readonly session: ClientGameSession;
283	  readonly depth: number;
284	  readonly startedAtMs: number;
285	}): Promise<void> => {
286	  const controllerState = await session.pollFloor(depth);
287	  patchCurrentTransition(get, set, {
288	    controllerState: controllerStateForStore(controllerState),
289	  });
290	
291	  const served = await session.resolveFloor(depth);
292	  const readyAtMs = nowMs();
293	  const transition = get().transition;
294	  if (
295	    transition === null ||
296	    transition.phase !== "descending" ||
297	    transition.depth !== depth ||
298	    transition.startedAtMs !== startedAtMs
299	  ) {
300	    return;
301	  }
302	
303	  set({
304	    transition: markTransitionFloorReady(
305	      transition,
306	      readyAtMs,
307	      served.source,
308	    ),
309	  });
310	  completeArrivalWhenReady(get, set);
311	
312	  const next = get().transition;
313	  if (next === null) {
314	    return;
315	  }
316	
317	  if (shouldAutoEnterFloor(next, nowMs())) {
318	    enterResolvedFloor(get, set);
319	    return;
320	  }
321	
322	  const delayMs = Math.max(0, READY_THEATER_MS - (nowMs() - next.startedAtMs));
323	  globalThis.setTimeout(() => {
324	    const current = get().transition;
325	    if (current !== null && shouldAutoEnterFloor(current, nowMs())) {
326	      enterResolvedFloor(get, set);
327	    }
328	  }, delayMs);
329	};
