 24	
 25	type RunEvent = Extract<RunLoopResult, { readonly ok: true }>["events"][number];
 26	
 27	export type ClientPrefetchState = "ready" | "in_flight" | "none";
 28	
 29	export type ClientServedFloorSource = "generated" | "fallback";
 30	
 31	export type ClientServedFloor = {
 32	  readonly depth: number;
 33	  readonly content: FloorContent;
 34	  readonly source: ClientServedFloorSource;
 35	};
 36	
 37	export type ClientTraceHeader = {
 38	  readonly recordType: "header";
 39	  readonly protocolVersion: GameState["version"]["protocolVersion"];
 40	  readonly engineVersion: string;
 41	  readonly modelId: string;
 42	  readonly contentRef: {
 43	    readonly providerId: string;
 44	    readonly packVersion: string;
 45	  };
 46	  readonly seed: string;
 47	  readonly createdAt: string;
 48	  readonly runId: string;
 49	};
