 51	export type ClientTraceTurn = {
 52	  readonly turn: number;
 53	  readonly action: RunAction;
 54	  readonly events: readonly RunEvent[];
 55	  readonly stateHash: string;
 56	};
 57	
 58	export type ClientParsedTrace = {
 59	  readonly header: ClientTraceHeader;
 60	  readonly turns: readonly ClientTraceTurn[];
 61	};
 62	
 63	export type ClientGameSessionStep = {
 64	  readonly state: GameState;
 65	  readonly events: readonly RunEvent[];
 66	};
 67	
 68	export type ClientGameSession = {
 69	  readonly state: GameState;
 70	  readonly createdAt: string;
 71	  readonly traceContent: string;
 72	  readonly parsedTrace: ClientParsedTrace;
 73	  readonly step: (action: RunAction) => ClientGameSessionStep;
 74	  readonly replaceState: (state: GameState) => void;
 75	  readonly setServedFloor: (served: ClientServedFloor) => void;
 76	  readonly pollFloor: (depth: number) => Promise<ClientPrefetchState>;
 77	  readonly resolveFloor: (depth: number) => Promise<ClientServedFloor>;
 78	  readonly prefetchNextFloor: () => void;
 79	};
 80	
 81	export type ClientGameSessionOptions = {
 82	  readonly seed: string;
 83	  readonly provider?: FloorContentProvider;
 84	  readonly restoredState?: GameState;
 85	  readonly restoredTraceContent?: string;
 86	};
 87	
 88	export const createClientGameSession = ({
 89	  seed,
 90	  provider = createFallbackFloorContentProvider(),
 91	  restoredState,
 92	  restoredTraceContent,
 93	}: ClientGameSessionOptions): ClientGameSession => {
 94	  const floorProvider = createClientServedFloorProvider(provider);
 95	  const started = startRun(seed, floorProvider);
 96	  if (!started.ok) {
 97	    throw new Error(started.error.message);
 98	  }
 99	
100	  let state = restoredState ?? started.state;
101	  const trace =
102	    restoredTraceContent === undefined
103	      ? createClientTrace({
104	          seed,
105	          createdAt: new Date().toISOString(),
106	          runId: state.run.runId,
107	          version: state.version,
108	        })
109	      : restoreClientTrace(restoredTraceContent) ??
110	        createClientTrace({
111	          seed,
112	          createdAt: new Date().toISOString(),
113	          runId: state.run.runId,
114	          version: state.version,
115	        });
116	  const createdAt = trace.header.createdAt;
117	
118	  return {
119	    get state() {
120	      return state;
121	    },
122	    get createdAt() {
123	      return createdAt;
124	    },
125	    get traceContent() {
126	      return trace.content;
127	    },
128	    get parsedTrace() {
129	      return trace.parsed;
130	    },
131	    step: (action) => {
132	      const before = state;
133	      const result = stepPlayerAction(before, action, floorProvider);
134	      if (!result.ok) {
135	        throw new Error(result.error.message);
136	      }
137	
138	      state = appendMissingReturnedEvents(before, result.state, result.events);
139	      trace.recordTurn(action, { state, events: result.events });
140	
141	      return {
142	        state,
143	        events: result.events,
144	      };
145	    },
146	    replaceState: (nextState) => {
147	      state = nextState;
148	    },
149	    setServedFloor: (served) => {
150	      floorProvider.setServedFloor(served);
151	    },
152	    pollFloor: (depth) => pollPrefetchStatus(state.run.runId, depth),
153	    resolveFloor: async (depth) => {
154	      const served = await resolvePrefetchedFloor(state.run.runId, depth, seed);
155	      floorProvider.setServedFloor(served);
156	      return served;
157	    },
158	    prefetchNextFloor: () => {
159	      void startPrefetchForCurrentFloor(state.run.runId, state.run.depth, trace.parsed);
160	    },
161	  };
162	};
163	
164	type ClientServedFloorProvider = FloorContentProvider & {
165	  readonly setServedFloor: (served: ClientServedFloor) => void;
166	};
167	
168	const createClientServedFloorProvider = (
169	  fallbackProvider: FloorContentProvider,
170	): ClientServedFloorProvider => {
171	  const servedFloors = new Map<number, ClientServedFloor>();
172	
173	  return {
174	    getFloor: (depth, seed) => {
175	      const served = servedFloors.get(depth);
176	      if (served === undefined) {
177	        return fallbackProvider.getFloor(depth, seed);
178	      }
179	
180	      servedFloors.delete(depth);
181	      return withSeed(served.content, seed);
182	    },
183	    setServedFloor: (served) => {
184	      servedFloors.set(served.depth, served);
185	    },
186	  };
187	};
188	
189	const withSeed = (content: FloorContent, seed: string): FloorContent => ({
190	  ...content,
191	  params: {
192	    ...content.params,
193	    seed,
194	  },
195	});
196	
197	const stepPlayerAction = (
198	  state: GameState,
199	  action: RunAction,
200	  provider: FloorContentProvider,
201	): RunLoopResult => {
202	  const turnBefore = state.run.turn;
203	  const shouldFreezeWorld = action.kind === "talk" || isWorldPaused(state);
204	  const result = stepRun(
205	    state,
206	    action,
207	    provider,
208	    { hooks: shouldFreezeWorld ? frozenWorldTurnHooks() : runGameplayTurnHooks() },
209	  );
210	
211	  if (!result.ok) {
212	    return result;
213	  }
214	
215	  let nextState = result.state;
216	  const events = [...result.events];
217	
218	  if (action.kind === "talk" || isWorldPaused(state) || isWorldPaused(nextState)) {
219	    nextState = freezeTurnCount(nextState, turnBefore);
220	  }
221	
222	  return {
223	    ok: true,
224	    state: nextState,
225	    events,
226	  };
227	};
228	
229	const frozenWorldTurnHooks = (): TurnHooks => ({
230	  actorTurn: ({ state }) => state,
231	  ticks: {
232	    damageOverTime: ({ state }) => state,
233	    durations: ({ state }) => state,
234	    hunger: ({ state }) => state,
235	    regen: ({ state }) => state,
236	  },
237	});
238	
239	const appendMissingReturnedEvents = (
240	  before: GameState,
241	  after: GameState,
242	  events: readonly RunEvent[],
243	): GameState => {
244	  const appendedCount = Math.max(0, after.log.length - before.log.length);
245	  if (appendedCount >= events.length) {
246	    return after;
247	  }
248	
249	  return {
250	    ...after,
251	    log: [...after.log, ...events.slice(appendedCount)],
252	  };
253	};
