255	type TraceVersion = {
256	  readonly protocolVersion: GameState["version"]["protocolVersion"];
257	  readonly engineVersion: string;
258	};
259	
260	const CONTENT_REF = {
261	  providerId: "fallback:old-stock",
262	  packVersion: "0.0.0",
263	} as const;
