265	const createClientTrace = ({
266	  seed,
267	  createdAt,
268	  runId,
269	  version,
270	}: {
271	  readonly seed: string;
272	  readonly createdAt: string;
273	  readonly runId: string;
274	  readonly version: TraceVersion;
275	}) => {
276	  const header: ClientTraceHeader = {
277	    recordType: "header",
278	    protocolVersion: version.protocolVersion,
279	    engineVersion: version.engineVersion,
280	    modelId: "web-client",
281	    contentRef: CONTENT_REF,
282	    seed,
283	    createdAt,
284	    runId,
285	  };
286	  const turns: ClientTraceTurn[] = [];
287	  const lines = [JSON.stringify(header)];
288	
289	  return {
290	    header,
291	    get content() {
292	      return `${lines.join("\n")}\n`;
293	    },
294	    get parsed(): ClientParsedTrace {
295	      return {
296	        header,
297	        turns: [...turns],
298	      };
299	    },
300	    recordTurn: (
301	      action: RunAction,
302	      result: ClientGameSessionStep,
303	    ): ClientTraceTurn => {
304	      const line: ClientTraceTurn = {
305	        turn: result.state.run.turn,
306	        action,
307	        events: result.events,
308	        stateHash: computeStateHash(result.state),
309	      };
310	      turns.push(line);
311	      lines.push(JSON.stringify(line));
312	      return line;
313	    },
314	  };
315	};
