317	const restoreClientTrace = (
318	  content: string,
319	): ReturnType<typeof createClientTrace> | null => {
320	  const lines = content
321	    .split(/\r?\n/u)
322	    .map((line) => line.trim())
323	    .filter((line) => line.length > 0);
324	  if (lines.length === 0) {
325	    return null;
326	  }
327	
328	  try {
329	    const header = JSON.parse(lines[0] ?? "") as ClientTraceHeader;
330	    if (header.recordType !== "header") {
331	      return null;
332	    }
333	    const turns = lines.slice(1).map((line) => JSON.parse(line) as ClientTraceTurn);
334	    const mutableLines = [...lines];
335	    const mutableTurns = [...turns];
336	
337	    return {
338	      header,
339	      get content() {
340	        return `${mutableLines.join("\n")}\n`;
341	      },
342	      get parsed(): ClientParsedTrace {
343	        return {
344	          header,
345	          turns: [...mutableTurns],
346	        };
347	      },
348	      recordTurn: (
349	        action: RunAction,
350	        result: ClientGameSessionStep,
351	      ): ClientTraceTurn => {
352	        const line: ClientTraceTurn = {
353	          turn: result.state.run.turn,
354	          action,
355	          events: result.events,
356	          stateHash: computeStateHash(result.state),
357	        };
358	        mutableTurns.push(line);
359	        mutableLines.push(JSON.stringify(line));
360	        return line;
361	      },
362	    };
363	  } catch {
364	    return null;
365	  }
366	};
