368	const computeStateHash = (state: GameState): string =>
369	  hashSerializedState(serialize(state));
370	
371	const FNV_OFFSET_BASIS = 0x811c9dc5;
372	const FNV_PRIME = 0x01000193;
373	
374	const hashSerializedState = (serialized: string): string => {
375	  let hash = FNV_OFFSET_BASIS;
376	
377	  for (let index = 0; index < serialized.length; index += 1) {
378	    hash ^= serialized.charCodeAt(index);
379	    hash = Math.imul(hash, FNV_PRIME) >>> 0;
380	  }
381	
382	  return hash.toString(16).padStart(8, "0");
383	};
