 19	export class FallbackProviderError extends Error {
 20	  readonly kind = "fallback-provider-error";
 21	  readonly code: FallbackProviderErrorCode;
 22	  readonly depth: number | null;
 23	  readonly file: string | null;
 24	  readonly entityId: string | null;
 25	  readonly source: unknown;
 26	
 27	  constructor(
 28	    code: FallbackProviderErrorCode,
 29	    depth: number | null,
 30	    message: string,
 31	    source: unknown,
 32	  ) {
 33	    super(message);
 34	    this.name = "FallbackProviderError";
 35	    this.code = code;
 36	    this.depth = depth;
 37	    this.source = source;
 38	
 39	    if (source instanceof FallbackContentValidationError) {
 40	      this.file = source.file;
 41	      this.entityId = source.entityId;
 42	      return;
 43	    }
 44	
 45	    this.file = null;
 46	    this.entityId = null;
 47	  }
 48	}
 49	
 50	export type FallbackFloorContentProviderOptions = {
 51	  readonly root?: URL;
 52	  readonly hoard?: HoardFeatureParams;
 53	};
 54	
 55	const DEFAULT_HOARD: HoardFeatureParams = {
 56	  id: "hoard",
 57	  name: "The Hoard",
 58	  hint: { distance: "far_from_entrance" },
 59	};
 60	
 61	export class FallbackFloorContentProvider implements FloorContentProvider {
 62	  readonly pack: FallbackContentPack;
 63	  private readonly floors: ReadonlyMap<number, ResolvedFallbackFloor>;
 64	  private readonly hoard: HoardFeatureParams;
 65	
 66	  constructor(options: FallbackFloorContentProviderOptions = {}) {
 67	    this.hoard = options.hoard ?? DEFAULT_HOARD;
 68	
 69	    try {
 70	      this.pack = loadFallbackContentPack(options.root);
 71	      this.floors = validateFloors(this.pack);
 72	    } catch (error) {
 73	      if (error instanceof FallbackProviderError) {
 74	        throw error;
 75	      }
 76	
 77	      throw wrapProviderError("fallback_content_invalid", null, error);
 78	    }
 79	  }
 80	
 81	  getFloor(depth: number, seed: string): FloorContent {
 82	    const floor = this.floors.get(depth);
 83	    if (floor === undefined) {
 84	      throw new FallbackProviderError(
 85	        "fallback_depth_unavailable",
 86	        depth,
 87	        `fallback floor ${depth} is not available`,
 88	        null,
 89	      );
 90	    }
 91	
 92	    return {
 93	      params: {
 94	        ...floor.params,
 95	        seed,
 96	        ...(depth === config.runStructure.depthFloors
 97	          ? { hoard: this.hoard }
 98	          : {}),
 99	      },
100	      roster: floor.roster,
101	      items: floor.items,
102	      traps: floor.traps,
103	      npcs: floor.npcs,
104	      ...(floor.quest === null ? {} : { quest: floor.quest }),
105	    };
106	  }
107	}
108	
109	export const createFallbackFloorContentProvider = (
110	  options: FallbackFloorContentProviderOptions = {},
111	): FallbackFloorContentProvider => new FallbackFloorContentProvider(options);
112	
113	const validateFloors = (
114	  pack: FallbackContentPack,
115	): ReadonlyMap<number, ResolvedFallbackFloor> => {
116	  const floors = new Map<number, ResolvedFallbackFloor>();
117	
118	  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
119	    try {
120	      floors.set(depth, getFallbackFloor(pack, depth));
121	    } catch (error) {
122	      throw wrapProviderError("fallback_content_invalid", depth, error);
123	    }
124	  }
125	
126	  return floors;
127	};
128	
129	const wrapProviderError = (
130	  code: FallbackProviderErrorCode,
131	  depth: number | null,
132	  source: unknown,
133	): FallbackProviderError => {
134	  const sourceMessage = source instanceof Error ? source.message : String(source);
135	  const message =
136	    depth === null
137	      ? `fallback content pack is invalid: ${sourceMessage}`
138	      : `fallback floor ${depth} is invalid: ${sourceMessage}`;
139	
140	  return new FallbackProviderError(code, depth, message, source);
141	};

