 46	export type RunControllerRegistry = {
 47	  readonly get: (runId: string) => PrefetchController | null;
 48	  readonly getOrCreate: (
 49	    runId: string,
 50	    options: PrefetchControllerOptions,
 51	  ) => PrefetchController;
 52	  readonly remove: (runId: string) => void;
 53	};
 54	
 55	export const createRunControllerRegistry = (): RunControllerRegistry => {
 56	  const controllers = new Map<string, PrefetchController>();
 57	
 58	  return {
 59	    get: (runId) => controllers.get(runId) ?? null,
 60	    getOrCreate: (runId, options) => {
 61	      const existing = controllers.get(runId);
 62	      if (existing !== undefined) {
 63	        return existing;
 64	      }
 65	
 66	      const created = createPrefetchController({ ...options, runId });
 67	      controllers.set(runId, created);
 68	      return created;
 69	    },
 70	    remove: (runId) => {
 71	      const controller = controllers.get(runId);
 72	      controller?.cancel();
 73	      controllers.delete(runId);
 74	    },
 75	  };
 76	};
