 78	export const createTransportHandlers = (
 79	  registry: RunControllerRegistry,
 80	  defaultOptions: Omit<PrefetchControllerOptions, "runId">,
 81	): TransportHandlers => ({
 82	  startGeneration: (request) => {
 83	    const controller = registry.getOrCreate(request.runId, {
 84	      ...defaultOptions,
 85	      runId: request.runId,
 86	    });
 87	    controller.onFloorEnter(request.depth, request.trace);
 88	    return { ok: true, prefetchDepth: request.depth + 1 };
 89	  },
 90	  pollStatus: (request) =>
 91	    registry.get(request.runId)?.pollStatus() ?? { status: "idle" },
 92	  getFloor: async (request) => {
 93	    const controller = registry.get(request.runId);
 94	    if (controller === null) {
 95	      throw new Error(`run ${request.runId} is not active`);
 96	    }
 97	
 98	    return controller.resolveFloor(request.depth, request.seed);
 99	  },
100	});
