102	type JsonRequest = {
103	  readonly action: "startGeneration" | "pollStatus" | "getFloor";
104	  readonly body: Record<string, unknown>;
105	};
106	
107	const readJsonBody = async (request: IncomingMessage): Promise<JsonRequest> => {
108	  const chunks: Buffer[] = [];
109	  for await (const chunk of request) {
110	    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
111	  }
112	
113	  return JSON.parse(Buffer.concat(chunks).toString("utf8")) as JsonRequest;
114	};
115	
116	const writeJson = (
117	  response: ServerResponse,
118	  statusCode: number,
119	  payload: unknown,
120	): void => {
121	  response.writeHead(statusCode, { "content-type": "application/json" });
122	  response.end(JSON.stringify(payload));
123	};
