125	export const createHttpHarness = (
126	  handlers: TransportHandlers,
127	): ReturnType<typeof createServer> =>
128	  createServer(async (request, response) => {
129	    if (request.method !== "POST" || request.url !== "/director") {
130	      writeJson(response, 404, { error: "not_found" });
131	      return;
132	    }
133	
134	    try {
135	      const payload = await readJsonBody(request);
136	      if (payload.action === "startGeneration") {
137	        writeJson(
138	          response,
139	          200,
140	          handlers.startGeneration(payload.body as StartGenerationRequest),
141	        );
142	        return;
143	      }
144	
145	      if (payload.action === "pollStatus") {
146	        writeJson(
147	          response,
148	          200,
149	          handlers.pollStatus(payload.body as PollStatusRequest),
150	        );
151	        return;
152	      }
153	
154	      if (payload.action === "getFloor") {
155	        const floor = await handlers.getFloor(payload.body as GetFloorRequest);
156	        writeJson(response, 200, floor);
157	        return;
158	      }
159	
160	      writeJson(response, 400, { error: "unknown_action" });
161	    } catch (error) {
162	      writeJson(response, 500, {
163	        error: error instanceof Error ? error.message : String(error),
164	      });
165	    }
166	  });
