391	const applySoftCap = (
392	  state: GameState,
393	  gameConfig: GameConfig
394	): { readonly state: GameState; readonly events: readonly RunEvent[] } => {
395	  const runtime = currentFloorRuntime(state);
396	  if (runtime === null) {
397	    return { state, events: [] };
398	  }
399	
400	  const floorTurn = state.run.turn - runtime.enteredTurn;
401	  const softCap = gameConfig.runStructure.perFloorSoftCapTurns;
402	  const interval = gameConfig.runStructure.reinforcementIntervalTurns;
403	
404	  if (floorTurn <= softCap || (floorTurn - softCap) % interval !== 0) {
405	    return { state, events: [] };
