428	  const cells = legalReinforcementCells(state);
429	  if (cells.length === 0) {
430	    const event = runEvent(state.run.turn, "run_boredom", {
431	      depth: state.run.depth,
432	      floorTurn,
433	      wave,
434	      budgetRemaining,
435	      reason: "no_legal_cell"
436	    });
437	    return { state: appendRunLog(state, [event]), events: [event] };
438	  }
439	
440	  const rng = runRng(state.run.seed).fork(
441	    `reinforcement:${state.run.depth}:${wave}`
442	  );
443	  const definition = rng.pick(candidates);
444	  const position = pickStable(cells, rng);
445	  const allocation = allocateEntityId(state.ids.entityCounters, "enemy");
446	  const entity = assembleEnemy(definition, {
447	    id: allocation.id,
448	    position
449	  });
450	  const cost = costOf(definition);
451	  const nextRuntime: FloorRuntime = {
452	    ...runtime,
453	    reinforcementSpawnBudgetSpent: runtime.reinforcementSpawnBudgetSpent + cost
454	  };
455	  const nextBudgetRemaining = Math.max(0, budgetRemaining - cost);
456	  const events = [
457	    runEvent(state.run.turn, "run_boredom", {
458	      depth: state.run.depth,
459	      floorTurn,
460	      wave,
461	      budgetRemaining,
462	      reason: "reinforcement_spawned"
463	    }),
464	    runEvent(state.run.turn, "run_reinforcement_spawned", {
465	      entityId: allocation.id,
466	      definitionId: definition.id,
467	      depth: state.run.depth,
468	      position,
469	      cost,
470	      budgetRemaining: nextBudgetRemaining,
471	      wave
472	    })
473	  ];
474	  const nextState = appendRunLog(
475	    withRuntime(
476	      {
477	        ...state,
478	        entities: {
479	          ...state.entities,
480	          [entity.id]: entity
481	        },
482	        ids: {
483	          ...state.ids,
484	          entityCounters: allocation.entityCounters
485	        }
486	      },
487	      nextRuntime
488	    ),
489	    events
490	  );
491	
492	  return { state: nextState, events };
493	};
