103	const waitForPromiseSync = <T>(
104	  promise: Promise<T>,
105	  timeoutMs: number,
106	  clock: PrefetchClock,
107	): T | null => {
108	  if (timeoutMs <= 0) {
109	    return null;
110	  }
111	
112	  const { port1, port2 } = new MessageChannel();
113	  let settled = false;
114	  let value: T | null = null;
115	
116	  void promise.then(
117	    (resolved) => {
118	      value = resolved;
119	      settled = true;
120	      port1.postMessage("done");
121	    },
122	    () => {
123	      settled = true;
124	      port1.postMessage("done");
125	    },
126	  );
127	
128	  const deadline = clock() + timeoutMs;
129	  while (!settled && clock() < deadline) {
130	    const remaining = deadline - clock();
131	    if (remaining <= 0) {
132	      break;
133	    }
134	
135	    waitOnPort(port2, Math.min(SYNC_WAIT_SLICE_MS, remaining));
136	  }
137	
138	  return settled ? value : null;
139	};
