10	export const assemblePrompt = (input: AssemblePromptInput): string => {
11	  const sections = [
12	    HARD_CANON_BLOCK,
13	    buildPersonaBlock(input.band),
14	    input.traceFacts.textBlock,
15	  ];
16	
17	  if (input.memoryBlock && input.memoryBlock.trim().length > 0) {
18	    sections.push(`CROSS-RUN MEMORY\n${input.memoryBlock.trim()}`);
19	  }
20	
21	  sections.push(
22	    buildTaskBlock({
23	      band: input.band,
24	      depth: input.depth,
25	      config: input.config,
26	      bounds: input.bounds,
27	      seed: input.runContext.seed,
28	      playerSummary: input.traceFacts.textBlock,
29	      signature: buildSignaturePromptPlan({
30	        band: input.band,
31	        config: input.config,
32	        bounds: input.bounds,
33	        signatureUsedThisRun: input.runContext.signatureMomentUsedThisRun,
34	      }),
35	    }),
36	  );
37	
38	  const prompt = sections.join("\n\n");
39	
40	  if (prompt.length > PROMPT_MAX_CHAR_LENGTH) {
41	    throw new Error(
42	      `assembled prompt exceeds budget (${prompt.length} > ${PROMPT_MAX_CHAR_LENGTH} chars)`,
43	    );
44	  }
45	
46	  return prompt;
47	};
