 86	const EntityArraySchema = <T extends z.ZodType>(schema: T, label: string) =>
 87	  z.array(schema).superRefine((entries, ctx) => {
 88	    const seen = new Set<string>();
 89	
 90	    for (const [index, entry] of entries.entries()) {
 91	      const parsed = schema.safeParse(entry);
 92	      if (!parsed.success) {
 93	        ctx.addIssue({
 94	          code: "custom",
 95	          path: [index],
 96	          message: `${label} validation failed`,
 97	        });
 98	        continue;
 99	      }
100	
101	      const id = (parsed.data as { id: string }).id;
102	      if (seen.has(id)) {
103	        ctx.addIssue({
104	          code: "custom",
105	          path: [index, "id"],
106	          message: `duplicate ${label} id ${id}`,
107	        });
108	      }
109	      seen.add(id);
110	    }
111	  });
