113	const readJsonFile = (path: URL | string): unknown => {
114	  try {
115	    return JSON.parse(readFileSync(path, "utf8")) as unknown;
116	  } catch (error) {
117	    const message = error instanceof Error ? error.message : String(error);
118	    throw new FallbackContentValidationError(path, null, message);
119	  }
120	};
