122	const parseEntityFile = <T>(
123	  filePath: URL,
124	  schema: z.ZodType<T>,
125	  label: string,
126	): ReadonlyMap<string, T> => {
127	  const raw = readJsonFile(filePath);
128	  const parsed = EntityArraySchema(schema, label).safeParse(raw);
129	
130	  if (!parsed.success) {
131	    throw new FallbackContentValidationError(
132	      filePath,
133	      null,
134	      parsed.error.message,
135	    );
136	  }
137	
138	  const map = new Map<string, T>();
139	
140	  for (const entry of parsed.data) {
141	    const itemParsed = schema.safeParse(entry);
142	    if (!itemParsed.success) {
143	      const id =
144	        typeof entry === "object" &&
145	        entry !== null &&
146	        "id" in entry &&
147	        typeof entry.id === "string"
148	          ? entry.id
149	          : null;
150	      throw new FallbackContentValidationError(
151	        filePath,
152	        id,
153	        itemParsed.error.message,
154	      );
155	    }
156	
157	    map.set((itemParsed.data as { id: string }).id, itemParsed.data);
158	  }
159	
160	  return map;
161	};
