163	const loadFloorFiles = (root: URL): ReadonlyMap<number, FallbackFloorDefinition> => {
164	  const floorsDir = new URL("floors/", root);
165	  const files = readdirSync(floorsDir, { withFileTypes: true })
166	    .filter((entry) => !entry.isDirectory() && entry.name.endsWith(".json"))
167	    .map((entry) => entry.name)
168	    .sort();
169	
170	  const map = new Map<number, FallbackFloorDefinition>();
171	
172	  for (const fileName of files) {
173	    const filePath = new URL(fileName, floorsDir);
174	    const raw = readJsonFile(filePath);
175	    const parsed = FallbackFloorDefinitionSchema.safeParse(raw);
176	
177	    if (!parsed.success) {
178	      throw new FallbackContentValidationError(
179	        filePath,
180	        null,
181	        parsed.error.message,
182	      );
183	    }
184	
185	    const depth = parsed.data.depth;
186	    if (map.has(depth)) {
187	      throw new FallbackContentValidationError(
188	        filePath,
189	        null,
190	        `duplicate floor depth ${depth}`,
191	      );
192	    }
193	
194	    map.set(depth, parsed.data);
195	  }
196	
197	  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
198	    if (!map.has(depth)) {
199	      throw new FallbackContentValidationError(
200	        new URL(`${depth}.json`, floorsDir).pathname,
201	        null,
202	        `missing floor definition for depth ${depth}`,
203	      );
204	    }
205	  }
206	
207	  return map;
208	};
