210	const resolveReferences = <T>(
211	  fileLabel: string,
212	  ids: readonly string[],
213	  table: ReadonlyMap<string, T>,
214	  entityLabel: string,
215	): readonly T[] =>
216	  ids.map((id) => {
217	    const entity = table.get(id);
218	    if (entity === undefined) {
219	      throw new FallbackContentValidationError(
220	        fileLabel,
221	        id,
222	        `unknown ${entityLabel} id ${id}`,
223	      );
224	    }
225	    return entity;
226	  });
