 92	export const transitionPresentation = (
 93	  transition: FloorTransitionState,
 94	  nowMs: number,
 95	): FloorTransitionPresentation => {
 96	  const elapsed = Math.max(0, nowMs - transition.startedAtMs);
 97	  const arrivalElapsed =
 98	    transition.arrivalStartedAtMs === null
 99	      ? 0
100	      : Math.max(0, nowMs - transition.arrivalStartedAtMs);
101	
102	  return {
103	    phase: transition.phase,
104	    floorLabel: `Floor ${transition.depth}`,
105	    whisper: transition.whisper,
106	    shimmerVisible:
107	      transition.phase === "descending" &&
108	      transition.controllerState === "in_flight" &&
109	      !transition.floorReady,
110	    shimmerPercent:
111	      transition.controllerState === "in_flight"
112	        ? Math.min(100, Math.round((elapsed / STAIRS_CAP_MS) * 100))
113	        : 0,
114	    awaitingFloor:
115	      transition.phase === "descending" &&
116	      transition.controllerState !== "ready" &&
117	      !transition.floorReady,
118	    skipEnabled:
119	      transition.phase === "descending" && transition.floorReady,
120	    arrivalProgress:
121	      transition.phase === "arrival"
122	        ? Math.min(1, arrivalElapsed / ARRIVAL_RITUAL_MS)
123	        : 0,
