 49	export class MemoryArtifactFs implements ArtifactFsAdapter {
 50	  readonly dirs = new Set<string>();
 51	  readonly files = new Map<string, string>();
 52	
 53	  makeDir(path: string): void {
 54	    this.dirs.add(path);
 55	  }
 56	
 57	  writeNewFile(path: string, contents: string): void {
 58	    if (this.files.has(path)) {
 59	      throw new Error(`file already exists: ${path}`);
 60	    }
 61	    this.files.set(path, contents);
 62	  }
 63	
 64	  writeFile(path: string, contents: string): void {
 65	    this.files.set(path, contents);
 66	  }
 67	
 68	  readFile(path: string): string {
 69	    const contents = this.files.get(path);
 70	    if (contents === undefined) {
 71	      throw new Error(`file does not exist: ${path}`);
 72	    }
 73	    return contents;
 74	  }
 75	
 76	  fileExists(path: string): boolean {
 77	    return this.files.has(path);
 78	  }
 79	
 80	  rename(from: string, to: string): void {
 81	    const contents = this.files.get(from);
 82	    if (contents === undefined) {
 83	      throw new Error(`file does not exist: ${from}`);
 84	    }
 85	    this.files.set(to, contents);
 86	    this.files.delete(from);
 87	  }
 88	
 89	  listEntries(path: string): readonly string[] {
 90	    const prefix = `${path}/`;
 91	    const entries = new Set<string>();
 92	
 93	    for (const filePath of this.files.keys()) {
 94	      if (!filePath.startsWith(prefix)) {
 95	        continue;
 96	      }
 97	      const remainder = filePath.slice(prefix.length);
 98	      const [entry] = remainder.split("/");
 99	      if (entry !== undefined && entry.length > 0) {
100	        entries.add(entry);
101	      }
102	    }
103	
104	    for (const dirPath of this.dirs) {
105	      if (!dirPath.startsWith(prefix)) {
106	        continue;
107	      }
108	      const remainder = dirPath.slice(prefix.length);
109	      const [entry] = remainder.split("/");
110	      if (entry !== undefined && entry.length > 0) {
111	        entries.add(entry);
112	      }
113	    }
114	
115	    return [...entries].sort();
116	  }
117	
118	  isDirectory(path: string): boolean {
119	    if (this.dirs.has(path)) {
120	      return true;
121	    }
122	
123	    const prefix = `${path}/`;
124	    return [...this.files.keys(), ...this.dirs].some((candidate) =>
125	      candidate.startsWith(prefix),
126	    );
127	  }
128	}

