377	const stepResolvedFloor = async (
378	  get: StoreGet,
379	  set: StoreSet,
380	  gameSession: ClientGameSession,
381	  transition: FloorTransitionState
382	): Promise<{
383	  readonly result: ClientGameSessionStep;
384	  readonly transition: FloorTransitionState;
385	} | null> => {
386	  try {
387	    return {
388	      result: gameSession.step({ kind: "descend" }),
389	      transition
390	    };
391	  } catch {
392	    const current = get().transition;
393	    if (!sameDescendingTransition(current, transition)) {
394	      return null;
395	    }
396	
397	    const fallback = await resolveFallbackAfterEntryFailure(
398	      gameSession,
399	      transition.depth
400	    );
401	    if (fallback === null) {
402	      clearFailedTransition(get, set);
403	      return null;
404	    }
405	
406	    if (fallback.source !== "fallback") {
407	      clearFailedTransition(get, set);
408	      return null;
409	    }
410	
411	    gameSession.setServedFloor(fallback);
412	
413	    const recovered = get().transition;
414	    if (!sameDescendingTransition(recovered, transition)) {
415	      return null;
416	    }
417	
418	    const fallbackTransition = markTransitionFloorReady(
419	      recovered,
420	      recovered.readyAtMs ?? nowMs(),
421	      "fallback"
422	    );
423	    set({ transition: fallbackTransition });
424	
425	    try {
426	      return {
427	        result: gameSession.step({ kind: "descend" }),
428	        transition: fallbackTransition
429	      };
430	    } catch {
